<template><div><div class="page-title">用户管理</div><div class="page-card"><div class="toolbar"><el-input v-model="query.username" placeholder="用户名" clearable style="width:180px"/><el-select v-model="query.role" placeholder="角色" clearable style="width:140px"><el-option label="管理员" value="ADMIN"/><el-option label="普通用户" value="USER"/><el-option label="维修人员" value="WORKER"/><el-option label="巡检人员" value="INSPECTOR"/></el-select><el-button type="primary" @click="loadData">查询</el-button><el-button type="success" @click="openAdd">新增用户</el-button></div><el-table :data="records" v-loading="loading" border><el-table-column prop="id" label="ID" width="80"/><el-table-column prop="username" label="用户名" width="140"/><el-table-column prop="realName" label="姓名" width="140"/><el-table-column prop="role" label="角色" width="140"/><el-table-column label="状态" width="100"><template #default="{row}"><el-tag :type="Number(row.status)===1?'success':'info'">{{ Number(row.status)===1?'启用':'禁用' }}</el-tag></template></el-table-column><el-table-column label="操作" width="240"><template #default="{row}"><el-button size="small" type="success" @click="changeStatus(row,1)">启用</el-button><el-button size="small" type="warning" @click="changeStatus(row,0)">禁用</el-button><el-button v-if="row.role==='WORKER'" size="small" @click="openSkill(row)">技能</el-button></template></el-table-column></el-table><el-pagination style="margin-top:16px" background layout="total, prev, pager, next, sizes" :total="total" v-model:current-page="query.pageNo" v-model:page-size="query.pageSize" @current-change="loadData" @size-change="loadData"/></div><el-dialog v-model="addVisible" title="新增用户" width="520px"><el-form :model="form" label-width="90px"><el-form-item label="用户名"><el-input v-model="form.username"/></el-form-item><el-form-item label="密码"><el-input v-model="form.password" type="password" show-password/></el-form-item><el-form-item label="姓名"><el-input v-model="form.realName"/></el-form-item><el-form-item label="角色"><el-select v-model="form.role" style="width:100%"><el-option label="管理员" value="ADMIN"/><el-option label="普通用户" value="USER"/><el-option label="维修人员" value="WORKER"/><el-option label="巡检人员" value="INSPECTOR"/></el-select></el-form-item></el-form><template #footer><el-button @click="addVisible=false">取消</el-button><el-button type="primary" @click="saveAdd">保存</el-button></template></el-dialog><el-dialog v-model="skillVisible" title="配置维修人员技能" width="480px"><el-input v-model="skillText" type="textarea" :rows="4" placeholder="例如：空调,电路,网络"/><template #footer><el-button @click="skillVisible=false">取消</el-button><el-button type="primary" @click="saveSkill">保存</el-button></template></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue';import { ElMessage } from 'element-plus';import { addUser,pageUsers,updateUserStatus,configureWorkerSkills } from '../api/user';const loading=ref(false),records=ref([]),total=ref(0);const query=reactive({pageNo:1,pageSize:10,username:'',role:''});const addVisible=ref(false),skillVisible=ref(false),currentWorker=ref(null),skillText=ref('');const form=reactive({username:'',password:'',realName:'',role:'USER'});async function loadData(){loading.value=true;try{const data=await pageUsers(query);records.value=data?.records||[];total.value=data?.total||0}finally{loading.value=false}}function openAdd(){Object.assign(form,{username:'',password:'',realName:'',role:'USER'});addVisible.value=true}async function saveAdd(){await addUser(form);ElMessage.success('新增成功');addVisible.value=false;loadData()}async function changeStatus(row,status){await updateUserStatus(row.id,{status});ElMessage.success('状态已修改');loadData()}function openSkill(row){currentWorker.value=row;skillText.value='';skillVisible.value=true}async function saveSkill(){const skills=skillText.value.split(',').map(i=>i.trim()).filter(Boolean);await configureWorkerSkills(currentWorker.value.id,{skills});ElMessage.success('技能已配置');skillVisible.value=false}onMounted(loadData)</script>
